const input = $json;

// =========================
// stdout extraction
// =========================
const stdout = input.stdout || "";
const date = new Date().toISOString();

// =========================
// parse résultat serveur
// =========================
let extracted = {};

// parse PC status
let data = {};

try {
  const serverMatch = stdout.match(/Résultat final :\n(\{[\s\S]*?\})\n\n/);

  if (serverMatch) {
    extracted = eval("(" + serverMatch[1] + ")");
  }

  const pcMatch = stdout.match(/DATA COMPLETE:\n(\{[\s\S]*?\})\n(?:✓|⚠|STATUS)/);

  if (pcMatch) {
    data = eval("(" + pcMatch[1] + ")");
  }

} catch (e) {
  extracted = { error: "parse failed" };
  data = {};
}

// =========================
// sécurité input
// =========================
const body = extracted || {};

// =========================
// variables directes
// =========================
const url = body.serveur;
const success = body.success;
const fail = Number(body.fail);
const taux = body.taux_reussite;
const temps_moyen = body.temps_moyen;
const rps = body.capacite_rps;
const etat = body.etat;

// =========================
// helper PC
// =========================
function has_error(data) {
  if (!data || !data.cpu) return false;

  return ["cpu", "ram", "disk", "temperature"].some(
    key =>
      data[key] &&
      ["orange", "red"].includes(data[key].zone)
  );
}

// =========================
// OUTPUT FINAL
// =========================
return [
  {
    json: {
      date: date,

      server: {
        url,
        status: etat
      },

      summary: {
        success,
        fail,
        taux_reussite: `${taux}%`
      },

      performance: {
        temps_moyen: `${temps_moyen}s`,
        rps
      },

      report: `SUCCESS ${success} / FAIL ${fail}`,

      interpretation: {
        message:
          etat === "Très stable"
            ? "Serveur en bonne santé"
            : "Problème détecté sur le serveur",

        advice:
          fail > 0
            ? "Vérifier la stabilité réseau ou backend"
            : "Aucune action requise"
      },

      pc_status: data,

      system_report: {
        alert: has_error(data),

        message:
          has_error(data)
            ? "Ressource système en alerte"
            : "Machine stable",

        advice:
          has_error(data)
            ? "Vérifier CPU / RAM / disque / température"
            : "Aucune action requise"
      }
    }
  }
];

